// src/App.jsx
import React, { useState, useEffect } from 'react';
import Login from './components/Login';
import Navbar from './components/Navbar';
import ProdutoLista from './components/ProdutoLista';
import ClienteForm from './components/ClienteForm';
import VendaForm from './components/VendaForm';
import './App.css';

function App() {
    const [isAuthenticated, setIsAuthenticated] = useState(false);
    const [activeTab, setActiveTab] = useState('produtos');

    useEffect(() => {
        const token = localStorage.getItem('token');
        if (token) {
            setIsAuthenticated(true);
        }
    }, []);

    const handleLogout = () => {
        localStorage.removeItem('token');
        setIsAuthenticated(false);
    };

    if (!isAuthenticated) {
        return <Login onLogin={() => setIsAuthenticated(true)} />;
    }

    return (
        <div>
            <Navbar activeTab={activeTab} setActiveTab={setActiveTab} onLogout={handleLogout} />
            <div style={styles.content}>
                {activeTab === 'produtos' && <ProdutoLista />}
                {activeTab === 'clientes' && <ClienteForm />}
                {activeTab === 'vendas' && <VendaForm />}
                {activeTab === 'relatorios' && <div style={styles.relatorios}>📊 Relatórios em breve...</div>}
            </div>
        </div>
    );
}

const styles = {
    content: {
        padding: '20px',
        backgroundColor: '#f5f5f5',
        minHeight: 'calc(100vh - 70px)'
    },
    relatorios: {
        textAlign: 'center',
        padding: '2rem',
        fontSize: '1.2rem',
        color: '#666'
    }
};

export default App;
